class Solution:
    def subarrayGCD(self, nums: List[int], k: int) -> int:
        def gcd(a, b):
            while b:
                a, b = b, a % b
            return a
        count = 0
        for i in range(len(nums)):
            curr_gcd = nums[i]
            for j in range(i, len(nums)):
                curr_gcd = gcd(curr_gcd, nums[j])
                if curr_gcd == k:
                    count += 1
        return count
